import 'package:vibration/vibration.dart'; class VibrationUtils { static Future<void> light() async { if (await Vibration.hasVibrator() ?? false) Vibration.vibrate(duration: 50); } static Future<void> medium() async { if (await Vibration.hasVibrator() ?? false) Vibration.vibrate(duration: 100); } static Future<void> heavy() async { if (await Vibration.hasVibrator() ?? false) Vibration.vibrate(duration: 300); } static Future<void> error() async { if (await Vibration.hasVibrator() ?? false) Vibration.vibrate(pattern: [0, 100, 50, 100]); } }